#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, X, K; scanf("%lld %lld %lld", &N, &X, &K);
        long long can = K / X;
        if(can > N) can = N;
        printf("%lld\n", can);
    }
    return 0;
}

